//! Repository for RfqItem entities
//!
//! Originally generated by metaphor-schema; now **user-owned** — this exact path is declared under
//! `user_owned` in `metaphor.codegen.yaml`, so the generator skips it wholesale. The custom methods
//! below hold the hand-written RfqItem SQL (4-layer rule: services orchestrate, repos hold SQL).
//!
//! Thin newtype over `backbone_orm::GenericCrudRepository<RfqItem, backbone_orm::SoftDelete>`.
//! All standard CRUD methods are available via `Deref`.

use anyhow::Result;
use rust_decimal::Decimal;
use sqlx::{PgPool, Row};
use uuid::Uuid;

use backbone_orm::company_scope;

use crate::domain::entity::RfqItem;

/// Table name for RfqItem entities
pub const TABLE_NAME: &str = "buying.rfq_items";

/// Repository for RfqItem entities.
///
/// All standard CRUD, soft-delete, pagination, and bulk methods are
/// provided automatically via `Deref` to `backbone_orm::GenericCrudRepository`.
pub struct RfqItemRepository(
    backbone_orm::GenericCrudRepository<RfqItem, backbone_orm::SoftDelete>,
);

impl std::ops::Deref for RfqItemRepository {
    type Target = backbone_orm::GenericCrudRepository<RfqItem, backbone_orm::SoftDelete>;
    fn deref(&self) -> &Self::Target { &self.0 }
}

impl RfqItemRepository {
    /// Create a new repository instance.
    pub fn new(pool: PgPool) -> Self {
        Self(backbone_orm::GenericCrudRepository::new(pool, TABLE_NAME))
    }
}

/// The exact row an RFQ line insert writes.
pub struct NewRfqItemRow {
    pub id: Uuid,
    pub rfq_id: Uuid,
    pub company_id: Uuid,
    pub item_id: Uuid,
    pub quantity: Decimal,
}

/// An RFQ line, as copied forward by the RFQ→SupplierQuotation funnel step.
pub struct RfqLineRow {
    pub item_id: Uuid,
    pub quantity: Decimal,
}

/// Hand-written RfqItem SQL. Lives here (not in the write service) per the module's 4-layer rule.
impl RfqItemRepository {
    /// Insert one RFQ line.
    ///
    /// Takes the CALLER'S connection so it commits with its header. The caller has already bound the
    /// company on it (`bind_company_on`) — don't re-bind here.
    pub async fn insert_item(
        &self,
        conn: &mut sqlx::PgConnection,
        l: &NewRfqItemRow,
    ) -> Result<(), sqlx::Error> {
        sqlx::query(
            "INSERT INTO buying.rfq_items (id, rfq_id, company_id, item_id, quantity) VALUES ($1,$2,$3,$4,$5)",
        )
        .bind(l.id).bind(l.rfq_id).bind(l.company_id).bind(l.item_id).bind(l.quantity)
        .execute(conn)
        .await?;
        Ok(())
    }

    /// Read an RFQ's lines for the RFQ→SupplierQuotation conversion. ID-only + scoped read.
    pub async fn fetch_lines(
        &self,
        pool: &PgPool,
        rfq_id: Uuid,
    ) -> Result<Vec<RfqLineRow>, sqlx::Error> {
        let rows = company_scope::fetch_all_rows_scoped(
            pool,
            sqlx::query(
                r#"SELECT item_id, quantity FROM buying.rfq_items
                   WHERE rfq_id=$1 AND (metadata->>'deleted_at') IS NULL"#,
            ).bind(rfq_id),
        )
        .await?;
        Ok(rows.iter().map(|r| RfqLineRow {
            item_id: r.get("item_id"),
            quantity: r.get("quantity"),
        }).collect())
    }
}

backbone_core::impl_crud_repository!(RfqItemRepository, RfqItem, soft_delete);
